import{_ as e,C as d,o as r,c as i,E as o,a3 as n}from"./chunks/framework.CVjg771q.js";const m=JSON.parse('{"title":"二十四节气","description":"中国人独有的时间刻度，将一年分为二十四份，每一份都有名字和诗意。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"二十四节气","description":"中国人独有的时间刻度，将一年分为二十四份，每一份都有名字和诗意。","outline":"deep"},"headers":[],"relativePath":"changshi/jieqi/index.md","filePath":"changshi/jieqi/index.md","lastUpdated":1779783531000}'),h={name:"changshi/jieqi/index.md"};function s(l,t,c,p,_,u){const a=d("DaoJieqi");return r(),i("div",null,[o(a),t[0]||(t[0]=n('<h2 id="关于二十四节气" tabindex="-1">关于二十四节气 <a class="header-anchor" href="#关于二十四节气" aria-label="Permalink to &quot;关于二十四节气&quot;">​</a></h2><h3 id="由来" tabindex="-1">由来 <a class="header-anchor" href="#由来" aria-label="Permalink to &quot;由来&quot;">​</a></h3><p>《千字文》道：&quot;治本于农，务兹稼穑。&quot;祖先观察太阳和四季变化，将时令、气候、物候记录下来，形成了「二十四节气」——一套指导农耕的知识体系。到秦汉年间已完全确立。</p><h3 id="为什么和公历吻合" tabindex="-1">为什么和公历吻合 <a class="header-anchor" href="#为什么和公历吻合" aria-label="Permalink to &quot;为什么和公历吻合&quot;">​</a></h3><p>节气观察的是太阳运转——作物依赖太阳而非月亮。因此节气日期与公历高度吻合。农历按月亮运行制定，而节气本质上是阳历——将黄道 24 等分，每等分 15°，每两个节气相差约 15 天。</p><h3 id="七十二候" tabindex="-1">七十二候 <a class="header-anchor" href="#七十二候" aria-label="Permalink to &quot;七十二候&quot;">​</a></h3><p>两个节气间的 15 天，又分三候，一候 5 天。共 72 候，是比节气更精细的自然观察尺度。如立春三候：一候东风解冻，二候蛰虫始振，三候鱼陟负冰。</p><h3 id="节气分类" tabindex="-1">节气分类 <a class="header-anchor" href="#节气分类" aria-label="Permalink to &quot;节气分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>节气</th></tr></thead><tbody><tr><td>寒暑变化</td><td>立春、春分、立夏、夏至、立秋、秋分、立冬、冬至</td></tr><tr><td>气温变化</td><td>小暑、大暑、处暑、小寒、大寒</td></tr><tr><td>降水量</td><td>雨水、谷雨、白露、寒露、霜降、小雪、大雪</td></tr><tr><td>物候现象</td><td>惊蛰、清明、小满、芒种</td></tr></tbody></table>',9))])}const b=e(h,[["render",s]]);export{m as __pageData,b as default};
